import{_ as e}from"./chunks/文件受限图.DsG20F9s.js";import{_ as a,o,c as l,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Moderazione immagini e modalità di accesso","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Safety/image-moderation-and-access-mode.md","filePath":"it-IT/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),n={name:"it-IT/Safety/image-moderation-and-access-mode.md"};function r(s,i,d,c,m,p){return o(),l("div",null,[...i[0]||(i[0]=[t('<h1 id="moderazione-immagini-e-modalita-di-accesso" tabindex="-1">Moderazione immagini e modalità di accesso <a class="header-anchor" href="#moderazione-immagini-e-modalita-di-accesso" aria-label="Permalink to &quot;Moderazione immagini e modalità di accesso&quot;">​</a></h1><p>La moderazione assegna una classificazione per età alle immagini caricate. La modalità di accesso decide quali classificazioni possono essere viste pubblicamente.</p><p>Questo influisce su gallery pubblica, URL pubblici dei file e Random Image API. Non limita il pannello admin: gli amministratori possono sempre vedere e gestire tutti i file.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri il pannello admin e vai a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Le impostazioni principali sono:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="a-cosa-serve-access-mode" tabindex="-1">A cosa serve Access Mode <a class="header-anchor" href="#a-cosa-serve-access-mode" aria-label="Permalink to &quot;A cosa serve Access Mode&quot;">​</a></h2><p>Access mode decide quali classificazioni per età possono essere mostrate pubblicamente.</p><p>Modalità attuali:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Classificazioni visibili pubblicamente</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Solo General</td></tr></tbody></table><p>Il default è Adult mode.</p><p>Per siti privati o con contenuti maturi, Adult mode può essere adatto. Per una gallery pubblica più prudente, scegli Youth, Teen o Child mode.</p><h2 id="cosa-succede-abilitando-la-moderazione" tabindex="-1">Cosa succede abilitando la moderazione <a class="header-anchor" href="#cosa-succede-abilitando-la-moderazione" aria-label="Permalink to &quot;Cosa succede abilitando la moderazione&quot;">​</a></h2><p>Quando la moderazione è attiva, ImgBed chiama il provider scelto durante l&#39;upload e salva la classificazione rilevata.</p><p>Classificazioni principali:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Significato</th></tr></thead><tbody><tr><td>General</td><td>Contenuto pubblico sicuro</td></tr><tr><td>R12</td><td>Contenuto lievemente sensibile</td></tr><tr><td>R16</td><td>Contenuto moderatamente sensibile</td></tr><tr><td>R18</td><td>Contenuto per adulti</td></tr></tbody></table><p>Il risultato viene usato per decidere l&#39;accesso pubblico.</p><p>Se la moderazione non è attiva, o i vecchi file non hanno rating, quei file restano non classificati. I file senza rating non vengono rimossi automaticamente dalla gallery pubblica o dalla Random Image API solo perché manca un risultato di moderazione.</p><h2 id="scegliere-un-provider-di-moderazione" tabindex="-1">Scegliere un provider di moderazione <a class="header-anchor" href="#scegliere-un-provider-di-moderazione" aria-label="Permalink to &quot;Scegliere un provider di moderazione&quot;">​</a></h2><p>I provider disponibili includono:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Ogni provider ha requisiti diversi:</p><ul><li>moderatecontent.com di solito richiede una API Key.</li><li>nsfwjs di solito richiede un URL endpoint API.</li><li>Sightengine richiede API user e API secret.</li></ul><p>Scegli in base al tuo account, alla disponibilità e alla qualità del rilevamento. Se moderazione è attiva e configurata correttamente, ImgBed prova a scrivere un rating durante l&#39;upload.</p><h2 id="effetto-sulla-gallery-pubblica" tabindex="-1">Effetto sulla gallery pubblica <a class="header-anchor" href="#effetto-sulla-gallery-pubblica" aria-label="Permalink to &quot;Effetto sulla gallery pubblica&quot;">​</a></h2><p>La gallery pubblica filtra i file in base alla modalità di accesso.</p><p>Esempi:</p><ul><li>Adult mode: le immagini R18 possono comparire.</li><li>Youth mode: le immagini R18 sono nascoste.</li><li>Teen mode: le immagini R16 e R18 sono nascoste.</li><li>Child mode: vengono mostrate solo immagini General.</li></ul><p>Questo vale solo per l&#39;accesso pubblico normale. Il pannello admin mostra comunque tutti i file.</p><h2 id="effetto-sugli-url-pubblici" tabindex="-1">Effetto sugli URL pubblici <a class="header-anchor" href="#effetto-sugli-url-pubblici" aria-label="Permalink to &quot;Effetto sugli URL pubblici&quot;">​</a></h2><p>Gli URL pubblici sono link diretti aperti dai visitatori.</p><p>Se il rating del file è consentito dalla modalità corrente, ImgBed restituisce l&#39;immagine originale.</p><p>Se il rating supera il livello consentito, l&#39;accesso pubblico normale non restituisce l&#39;originale. ImgBed restituisce invece il risultato bloccato o l&#39;immagine sostitutiva configurata.</p><p>Esempio:</p><ul><li>La modalità corrente è Child mode.</li><li>Un&#39;immagine è classificata R18.</li><li>Un visitatore apre direttamente l&#39;URL pubblico.</li><li>ImgBed non restituisce a quel visitatore l&#39;immagine R18 originale.</li></ul><p><img src="'+e+'" alt="Immagine file limitata" loading="lazy"></p><p>Gli amministratori nel pannello admin non sono interessati da questa limitazione.</p><h2 id="effetto-sulla-random-image-api" tabindex="-1">Effetto sulla Random Image API <a class="header-anchor" href="#effetto-sulla-random-image-api" aria-label="Permalink to &quot;Effetto sulla Random Image API&quot;">​</a></h2><p>Anche la Random Image API filtra il proprio insieme di candidati secondo la modalità di accesso.</p><p>In Child mode, le immagini casuali vengono scelte solo tra file General.</p><p>In Youth mode, possono arrivare da file General, R12 e R16, ma non R18.</p><p>Così la Random Image API non può aggirare le restrizioni della gallery pubblica.</p><h2 id="rapporto-con-allowlist-e-blocklist" tabindex="-1">Rapporto con allowlist e blocklist <a class="header-anchor" href="#rapporto-con-allowlist-e-blocklist" aria-label="Permalink to &quot;Rapporto con allowlist e blocklist&quot;">​</a></h2><p>Access mode non è l&#39;unica regola di accesso pubblico. Lavora insieme ad allowlist e blocklist.</p><p>In breve:</p><ul><li>I contenuti in allowlist sono pubblici per primi.</li><li>I contenuti in blocklist non possono essere visti direttamente dai visitatori normali.</li><li>I contenuti non presenti in nessuna lista vengono poi controllati rispetto ad access mode.</li></ul><p>Se un&#39;immagine è limitata sia dal rating sia dalle regole di lista, i visitatori normali non possono comunque vedere il file originale direttamente.</p><h2 id="impostazioni-consigliate" tabindex="-1">Impostazioni consigliate <a class="header-anchor" href="#impostazioni-consigliate" aria-label="Permalink to &quot;Impostazioni consigliate&quot;">​</a></h2><p>Per siti pubblici:</p><ul><li>Abilita la moderazione.</li><li>Scegli una modalità adatta al pubblico del sito.</li><li>Usa Child mode o Teen mode per visitatori di tutte le età.</li><li>Evita Adult mode se non vuoi mostrare contenuti maturi pubblicamente.</li><li>Controlla i rating nel pannello admin e correggili manualmente quando serve.</li></ul><p>Per siti privati o personali:</p><ul><li>Adult mode di solito va bene.</li><li>Abilita la moderazione se ti è utile.</li><li>Rivedi e correggi i rating nel pannello admin quando necessario.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="i-file-spariscono-dal-pannello-admin-se-cambio-access-mode" tabindex="-1">I file spariscono dal pannello admin se cambio Access Mode? <a class="header-anchor" href="#i-file-spariscono-dal-pannello-admin-se-cambio-access-mode" aria-label="Permalink to &quot;I file spariscono dal pannello admin se cambio Access Mode?&quot;">​</a></h3><p>No.</p><p>Access mode riguarda solo l&#39;accesso pubblico normale. Non influisce sul pannello admin.</p><h3 id="perche-la-gallery-pubblica-mostra-meno-immagini-in-child-mode" tabindex="-1">Perché la gallery pubblica mostra meno immagini in Child mode? <a class="header-anchor" href="#perche-la-gallery-pubblica-mostra-meno-immagini-in-child-mode" aria-label="Permalink to &quot;Perché la gallery pubblica mostra meno immagini in Child mode?&quot;">​</a></h3><p>Child mode consente pubblicamente solo file General. R12, R16 e R18 vengono filtrati.</p><h3 id="gli-url-pubblici-possono-ancora-aprire-immagini-per-adulti" tabindex="-1">Gli URL pubblici possono ancora aprire immagini per adulti? <a class="header-anchor" href="#gli-url-pubblici-possono-ancora-aprire-immagini-per-adulti" aria-label="Permalink to &quot;Gli URL pubblici possono ancora aprire immagini per adulti?&quot;">​</a></h3><p>Se la modalità corrente non consente quel rating, gli URL pubblici normali non restituiscono l&#39;immagine originale.</p><h3 id="la-random-image-api-puo-restituire-immagini-limitate" tabindex="-1">La Random Image API può restituire immagini limitate? <a class="header-anchor" href="#la-random-image-api-puo-restituire-immagini-limitate" aria-label="Permalink to &quot;La Random Image API può restituire immagini limitate?&quot;">​</a></h3><p>No.</p><p>La Random Image API filtra i candidati secondo la modalità di accesso corrente.</p><h3 id="cosa-succede-ai-vecchi-file-senza-rating" tabindex="-1">Cosa succede ai vecchi file senza rating? <a class="header-anchor" href="#cosa-succede-ai-vecchi-file-senza-rating" aria-label="Permalink to &quot;Cosa succede ai vecchi file senza rating?&quot;">​</a></h3><p>Le immagini senza rating non vengono nascoste automaticamente solo perché non hanno risultato di moderazione. Puoi correggere il rating in seguito dal pannello admin.</p>',67)])])}const h=a(n,[["render",r]]);export{b as __pageData,h as default};
